func (m *PowerEvent) validate(all bool) error {
	if m == nil {
		return nil
	}

	var errors []error

	// no validation rules for ComponentName

	// no validation rules for EventType

	if all {
		switch v := interface{}(m.GetTimestamp()).(type) {
		case interface{ ValidateAll() error }:
			if err := v.ValidateAll(); err != nil {
				errors = append(errors, PowerEventValidationError{
					field:  "Timestamp",
					reason: "embedded message failed validation",
					cause:  err,
				})
			}
		case interface{ Validate() error }:
			if err := v.Validate(); err != nil {
				errors = append(errors, PowerEventValidationError{
					field:  "Timestamp",
					reason: "embedded message failed validation",
					cause:  err,
				})
			}
		}
	} else if v, ok := interface{}(m.GetTimestamp()).(interface{ Validate() error }); ok {
		if err := v.Validate(); err != nil {
			return PowerEventValidationError{
				field:  "Timestamp",
				reason: "embedded message failed validation",
				cause:  err,
			}
		}
	}

	if m.EventData != nil {
		// no validation rules for EventData
	}

	if m.Severity != nil {
		// no validation rules for Severity
	}

	if len(errors) > 0 {
		return PowerEventMultiError(errors)
	}

	return nil
}

// PowerEventMultiError is an error wrapping multiple validation errors
// returned by PowerEvent.ValidateAll() if the designated constraints aren't met.
type PowerEventMultiError []error

// Error returns a concatenation of all the error messages it wraps.
func (m PowerEventMultiError) Error() string {
	msgs := make([]string, 0, len(m))
	for _, err := range m {
		msgs = append(msgs, err.Error())
	}
	return strings.Join(msgs, "; ")
}

// AllErrors returns a list of validation violation errors.
func (m PowerEventMultiError) AllErrors() []error { return m }

// PowerEventValidationError is the validation error returned by
// PowerEvent.Validate if the designated constraints aren't met.
type PowerEventValidationError struct {
	field  string
	reason string
	cause  error
	key    bool
}

// Field function returns field value.
func (e PowerEventValidationError) Field() string { return e.field }

// Reason function returns reason value.
func (e PowerEventValidationError) Reason() string { return e.reason }

// Cause function returns cause value.
func (e PowerEventValidationError) Cause() error { return e.cause }

// Key function returns key value.
func (e PowerEventValidationError) Key() bool { return e.key }

// ErrorName returns error name.
func (e PowerEventValidationError) ErrorName() string { return "PowerEventValidationError" }

// Error satisfies the builtin error interface
func (e PowerEventValidationError) Error() string {
	cause := ""
	if e.cause != nil {
		cause = fmt.Sprintf(" | caused by: %v", e.cause)
	}

	key := ""
	if e.key {
		key = "key for "
	}

	return fmt.Sprintf(
		"invalid %sPowerEvent.%s: %s%s",
		key,
		e.field,
		e.reason,
		cause)
}

var _ error = PowerEventValidationError{}

var _ interface {
	Field() string
	Reason() string
	Key() bool
	Cause() error
	ErrorName() string
} = PowerEventValidationError{}
